async function uploadPlugin(){if(adminControls.disablePluginUpload&&localStorage.getItem('username')!=='admin'){showModal('提示','管理员已禁用插件上传');return;}const input=document.createElement('input');input.type='file';input.accept='.zip,.7z,.rar';input.onchange=async function(e){const file=e.target.files[0];if(!file)return;const formData=new FormData();formData.append('plugin',file);formData.append('token',token);showUploadProgressModal(1);try{const res=await fetch('/api/upload-plugin',{method:'POST',body:formData});const data=await res.json();if(data.success){showModal('成功','插件上传成功');loadPlugins();}else{showModal('错误',data.error||'上传失败');}}catch(e){showModal('错误','上传失败');}closeUploadModal();};input.click();}
function showUploadProgressModal(totalFiles){const modal=document.getElementById('modal');if(!modal)return;const titleEl=document.getElementById('modalTitle');if(titleEl)titleEl.innerText='上传进度';let progressHtml='';for(let i=0;i<totalFiles;i++){progressHtml+=`<div style="margin-bottom:10px;"><div>文件 ${i+1}</div><div class="progress-bar" style="width:100%;height:20px;background:#f0f0f0;border-radius:10px;"><div id="progress-${i}" class="progress-fill" style="width:0%;height:20px;background:#1976d2;border-radius:10px;transition:width 0.3s;"></div></div></div>`;}const messageEl=document.getElementById('modalMessage');if(messageEl)messageEl.innerHTML=progressHtml;const inputEl=document.getElementById('modalInput');if(inputEl)inputEl.style.display='none';const frameworkSelect=document.getElementById('frameworkSelect');if(frameworkSelect)frameworkSelect.style.display='none';const profileFields=document.getElementById('profileFields');if(profileFields)profileFields.style.display='none';const passwordFields=document.getElementById('passwordFields');if(passwordFields)passwordFields.style.display='none';modal.style.display='flex';const confirmBtn=document.getElementById('modalConfirm');const cancelBtn=document.getElementById('modalCancel');if(confirmBtn)confirmBtn.style.display='none';if(cancelBtn){cancelBtn.innerText='取消上传';cancelBtn.style.display='inline-block';cancelBtn.onclick=()=>{if(window.uploadXHR)window.uploadXHR.abort();closeUploadModal();};}}
