function renderProviderCards(){const list=document.getElementById('providerList');if(!list)return;let html='<div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(300px,1fr));gap:20px;">';providers.forEach(p=>{html+=`<div class="provider-card" data-id="${p.id}" style="opacity:${p.enabled===false?0.6:1};min-height:120px;"><div style="display:flex;justify-content:space-between;align-items:flex-start;"><div style="flex:1;"><div style="font-size:18px;font-weight:600;">${escapeHtml(p.name)}</div><div style="font-size:12px;color:#666;word-break:break-all;">${escapeHtml(p.url)}</div></div><img src="${p.icon}" style="width:48px;height:48px;border-radius:12px;opacity:0.4;object-fit:contain;" onerror="this.src='/image/user.svg'"></div><div style="display:flex;margin-top:16px;"><div style="display:flex;gap:6px;"><button class="provider-btn" style="background:#f0e6ff;color:#9c27b0;border-color:#ce93d8;padding:4px 8px;font-size:11px;" onclick="showModelsModal('${p.id}')"><i data-feather="list" style="width:14px;height:14px;"></i>列表</button><button class="provider-btn" style="background:#ffebee;color:#d32f2f;border-color:#ef9a9a;padding:4px 8px;font-size:11px;" onclick="deleteProvider('${p.id}');event.stopPropagation();"><i data-feather="trash-2" style="width:14px;height:14px;"></i>删除</button><button class="provider-btn" style="background:#f5f5f7;color:#000;border-color:#ddd;padding:4px 8px;font-size:11px;" onclick="editProvider('${p.id}');event.stopPropagation();"><i data-feather="edit-2" style="width:14px;height:14px;"></i>编辑</button><button class="provider-btn" style="background:#e3f2fd;color:#1976d2;border-color:#90caf9;padding:4px 8px;font-size:11px;" onclick="testProvider('${p.id}');event.stopPropagation();"><i data-feather="check-circle" style="width:14px;height:14px;"></i>测试</button></div></div></div>`;});html+='</div>';list.innerHTML=html;feather.replace();}
function showModelsModal(providerId){let p=providers.find(p=>p.id===providerId);if(!p||!p.models||!p.models.length){showModal('模型列表','暂无模型数据',false);return;}let list='<div style="max-height:300px;overflow-y:auto;">';p.models.forEach(m=>{list+=`<div style="padding:8px 12px;border-bottom:1px solid #f0f0f0;font-family:monospace;">${escapeHtml(m)}</div>`;});list+='</div>';showModal(`${p.name} 模型列表`,list,false);feather.replace();}
function editProvider(providerId){const provider=providers.find(p=>p.id===providerId);if(!provider)return;const form=`<div style="display:flex;flex-direction:column;gap:8px;"><div><div style="font-size:14px;font-weight:500;margin-bottom:2px">名称</div><input id="edit-name" class="modal-input" value="${escapeHtml(provider.name)}"></div><div><div style="font-size:14px;font-weight:500;margin-bottom:2px">聊天URL</div><input id="edit-url" class="modal-input" value="${escapeHtml(provider.url)}"></div><div><div style="font-size:14px;font-weight:500;margin-bottom:2px">模型列表URL</div><input id="edit-modelsUrl" class="modal-input" value="${escapeHtml(provider.modelsUrl)}"></div><div><div style="font-size:14px;font-weight:500;margin-bottom:2px">API Key</div><input id="edit-key" class="modal-input" value="${escapeHtml(provider.keys[0]?.key||'')}"></div><div><div style="font-size:14px;font-weight:500;margin-bottom:2px">图标URL</div><input id="edit-icon" class="modal-input" value="${escapeHtml(provider.icon)}"></div></div>`;showModal('编辑提供商',form,true,async()=>{const name=document.getElementById('edit-name').value;const url=document.getElementById('edit-url').value;const modelsUrl=document.getElementById('edit-modelsUrl').value;const key = document.getElementById('edit-key')?.value || '';const icon=document.getElementById('edit-icon').value;const defaultModel=document.getElementById('edit-defaultModel');const updated={...provider,name,url,modelsUrl,icon,defaultModel};if(provider.keys.length===0)provider.keys.push({id:'key1',key:'',isActive:true});updated.keys=[{...provider.keys[0],key}];try{await fetch(`/api/providers/${providerId}?token=${token}`,{method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify(updated)});loadProviders();}catch(e){}},'',false);feather.replace();}
