async function testProvider(providerId){const provider=providers.find(p=>p.id===providerId);if(!provider)return;const activeKey=provider.keys?.find(k=>k.isActive)?.key;if(!activeKey){showModal('测试失败','请先配置API Key');return;}try{const res=await fetch(`/api/providers/${providerId}/models?token=${token}`);const models=await res.json();if(models&&models.length>0){let msg=`可用模型列表:<br>${models.map(m=>'✅ '+m).join('<br>')}`;showModal('测试成功',msg);provider.models=models;renderProviderCards();}else{showModal('测试失败','未获取到模型列表');}}catch(e){showModal('测试失败',e.message);}}
