function getMessageActions(index,role){let buttons='<div class="message-actions">';buttons+=`<button class="message-copy-btn" onclick="copyMessage(${index}, '${role}')"><svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="9" y="9" width="13" height="13" rx="2" ry="2"></rect><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"></path></svg></button>`;buttons+=`<button class="message-edit-btn" onclick="editMessage(${index}, '${role}')"><svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M20 14.66V20a2 2 0 0 1-2 2H4a2 2 0 0 1-2-2V6a2 2 0 0 1 2-2h5.34"></path><polygon points="18 2 22 6 12 16 8 16 8 12 18 2"></polygon></svg></button>`;buttons+=`<button class="message-delete-btn" onclick="deleteMessage(${index}, '${role}')"><svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polyline points="3 6 5 6 21 6"></polyline><path d="M19 6v14a2 2 0 0 1-2 2H7a2 2 0 0 1-2-2V6m3 0V4a2 2 0 0 1 2-2h4a2 2 0 0 1 2 2v2"></path><line x1="10" y1="11" x2="10" y2="17"></line><line x1="14" y1="11" x2="14" y2="17"></line></svg></button>`;if(role==='assistant'){buttons+=`<button class="message-regenerate-btn" onclick="regenerateMessage(${index}, '${role}')"><svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polyline points="23 4 23 10 17 10"></polyline><polyline points="1 20 1 14 7 14"></polyline><path d="M3.51 9a9 9 0 0 1 14.85-3.36L23 10M1 14l4.64 4.36A9 9 0 0 0 20.49 15"></path></svg></button>`;}buttons+='</div>';return buttons;}
function escapeHtml(text){const div=document.createElement('div');div.textContent=text;return div.innerHTML;}
function previewMedia(src,type){let content='';if(type.startsWith('image/')){content=`<img src="${src}" style="max-width:100%;max-height:80vh;">`;}else if(type.startsWith('video/')){content=`<video src="${src}" controls style="max-width:100%;max-height:80vh;"></video>`;}else if(type.startsWith('audio/')){content=`<audio src="${src}" controls></audio>`;}else{content=`<pre>${escapeHtml(atob(src.split(',')[1]||''))}</pre>`;}showModal('预览',content,false);}
async function loadHistories(){if(!token)return;try{const res=await fetch(`/api/histories?token=${token}`);const histories=await res.json();const list=document.getElementById('historyList');if(list){const items=Object.values(histories);if(items.length===0){list.innerHTML='<div style="padding:20px;text-align:center;color:#999;">暂无历史会话</div>';}else{list.innerHTML=items.sort((a,b)=>new Date(b.createdAt)-new Date(a.createdAt)).map(h=>`<div class="history-item" data-id="${h.id}"><div style="font-weight:500;">${escapeHtml(h.title||'新对话')}</div><div style="font-size:12px;color:#666;margin-top:4px;">${new Date(h.createdAt).toLocaleString()}</div><button class="delete-history" onclick="deleteHistory('${h.id}');event.stopPropagation();">删除</button></div>`).join('');document.querySelectorAll('.history-item').forEach(el=>{el.onclick=async function(){currentHistoryId=this.dataset.id;localStorage.setItem('currentHistoryId',currentHistoryId);await loadHistoryById(currentHistoryId);document.querySelector('.nav-item[data-pane="chat"]').click();};});}}}catch(e){console.error('加载历史失败:',e);}}
async function loadFiles(dir=''){try{const res=await fetch(`/api/files?token=${token}&path=${encodeURIComponent(dir)}&folder=${encodeURIComponent(currentPublicFolder)}`);const files=await res.json();files.forEach(f=>folderStatuses[f.path]=f.status);currentFilePath=dir;updatePathBreadcrumbs(dir);const grid=document.getElementById('filesGrid');if(grid){grid.innerHTML=files.map(f=>`<div class="file-card ${selectedFiles.includes(f.path)?'selected':''}" onclick="toggleFileSelect('${f.path}')" ondblclick="viewFile('${f.path}', '${escapeHtml(f.name)}', ${f.isDirectory})"><div style="font-size:24px;margin-bottom:8px;">${f.isDirectory?'<i data-feather="folder"></i>':'<i data-feather="file"></i>'}</div><div style="font-weight:500;margin-bottom:4px;">${escapeHtml(f.name)}</div><div style="font-size:12px;color:#666;">${f.isDirectory?'文件夹':(f.size/1024).toFixed(1)+' KB'} ${f.status==='private'?'<i data-feather="lock"></i>':''}</div><div class="file-actions"><button class="file-btn" onclick="event.stopPropagation();renameFile('${f.path}','${escapeHtml(f.name)}')"><i data-feather="edit-2"></i></button><button class="file-btn" onclick="event.stopPropagation();moveFile('${f.path}')"><i data-feather="package"></i></button><button class="file-btn" onclick="event.stopPropagation();deleteFile('${f.path}')"><i data-feather="trash-2"></i></button><button class="file-btn" onclick="event.stopPropagation();sendToChat('${f.path}')"><i data-feather="message-square"></i></button></div></div>`).join('');feather.replace();}}catch(e){}}
function updatePathBreadcrumbs(dir){const pathDiv=document.getElementById('folderPath');if(!pathDiv)return;const parts=dir.split('/').filter(p=>p);let html='<span class="path-item" onclick="navigateTo(\'\')">公共</span>';let current='';parts.forEach((part,i)=>{current+=(i>0?'/':'')+part;html+=`<span> / </span><span class="path-item" onclick="navigateTo('${current}')">${escapeHtml(part)}</span>`;});pathDiv.innerHTML=html;}
async function loadNotice(){try{const res=await fetch(`/api/notice/${currentLang}`);const data=await res.json();document.getElementById('noticeEditor').value=data.content;}catch(e){}}
async function loadOnlineCount(){try{const res=await fetch('/api/online-count');const data=await res.json();onlineCount=data.count;document.getElementById('onlineCount').innerText=onlineCount;}catch(e){}}
async function loadMyIP(){try{const res=await fetch('/api/my-ip');const data=await res.json();myIP=data.ip;document.getElementById('myIP').innerText=myIP;}catch(e){}}



function closeModalWithAnimation(modal, callback){modal.classList.add('exit');setTimeout(()=>{modal.style.display='none';modal.classList.remove('exit');if(callback)callback();},200);}
async function loadModelStatsData(){try{const res=await fetch(`/api/model-stats?token=${token}`);const data=await res.json();document.getElementById('totalStatsCalls').innerText=data.totalCalls;const list=document.getElementById('statsList');if(list){if(data.stats.length===0){list.innerHTML='<div style="padding:20px;text-align:center;color:#999;">暂无调用记录</div>';}else{list.innerHTML=data.stats.map(s=>`<div style="display:flex;justify-content:space-between;align-items:center;padding:12px;background:white;border-radius:16px;border:1px solid #f0f0f0;"><div><span style="font-weight:600;">${escapeHtml(s.provider)}</span><span style="margin-left:12px;font-family:monospace;">${escapeHtml(s.model)}</span></div><div><span style="font-size:20px;font-weight:600;">${s.count}</span><span style="margin-left:8px;color:#666;">次</span></div></div>`).join('');}}}catch(e){}}






function renderPrivateChats(){const list=document.getElementById('privateChatList');if(!list)return;const sorted=[...privateChats].sort((a,b)=>{if(a.pinned!==b.pinned)return a.pinned?-1:1;return b.lastMessageTime-a.lastMessageTime;});list.innerHTML=sorted.map(c=>`<div class="private-chat-item" onclick="selectPrivateUser('${c.friend}')"><span>${escapeHtml(c.friend)}</span><div><button class="chat-pin-btn" onclick="event.stopPropagation();pinChat('${c.friend}',${!c.pinned})">${c.pinned?'📌':'📍'}</button><button class="chat-delete-btn" onclick="event.stopPropagation();deleteChat('${c.friend}')">🗑️</button></div></div>`).join('');}

async function saveNotice(){if(adminControls.disableNoticeEdit&&localStorage.getItem('username')!=='admin'){showModal('提示','管理员已禁用须知编辑');return;}const content=document.getElementById('noticeEditor').value;try{await fetch(`/api/notice/${currentLang}`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({content})});const now=new Date();noticeLastSaved=`${now.getFullYear()}-${(now.getMonth()+1).toString().padStart(2,'0')}-${now.getDate().toString().padStart(2,'0')} ${now.getHours().toString().padStart(2,'0')}:${now.getMinutes().toString().padStart(2,'0')}:${now.getSeconds().toString().padStart(2,'0')}`;document.getElementById('noticeSavedTime').innerText=`上次保存: ${noticeLastSaved}`;if(currentConfigs.markdown){document.getElementById('noticePreview').innerHTML=marked.parse(content);}else{document.getElementById('noticePreview').innerText=content;}toggleNoticeEdit();}catch(e){}}
document.getElementById('langZhBtn')?.addEventListener('click',()=>{currentLang='zh';document.getElementById('langZhBtn').classList.add('active');document.getElementById('langEnBtn').classList.remove('active');loadNotice();});document.getElementById('langEnBtn')?.addEventListener('click',()=>{currentLang='en';document.getElementById('langEnBtn').classList.add('active');document.getElementById('langZhBtn').classList.remove('active');loadNotice();});
function renderOperations(historyId){const ops=fileOperations[historyId]||[];const container=document.getElementById('operationsList');if(!container)return;if(ops.length===0){container.innerHTML='<div style="padding:20px;text-align:center;color:#999;">暂无操作记录</div>';return;}let html='';ops.forEach(op=>{const icon=op.success?'✅':'❌';const color=op.success?'#4caf50':'#f44336';html+=`<div class="operation-item" style="padding:12px;border-bottom:1px solid #f0f0f0;display:flex;align-items:center;gap:12px;"><span style="font-size:20px;">${icon}</span><div style="flex:1;"><div style="font-weight:500;">${op.type||'未知操作'}</div><div style="font-size:13px;color:#666;word-break:break-all;">${op.path||op.url||''}</div>${op.error?`<div style="font-size:12px;color:${color};">错误: ${op.error}</div>`:''}</div></div>`;});container.innerHTML=html;}


function toggleFullscreen(){if(!document.fullscreenElement){document.documentElement.requestFullscreen();}else{if(document.exitFullscreen){document.exitFullscreen();}}}
function showKeysModal(){let html='<div style="max-height:400px;overflow-y:auto;">';providers.forEach(p=>{const activeKey=p.keys?.find(k=>k.isActive);if(activeKey&&activeKey.key){html+=`<div style="margin-bottom:16px;padding:12px;background:#f5f5f7;border-radius:12px;"><div style="font-weight:600;margin-bottom:4px;">${escapeHtml(p.name)}</div><div style="font-family:monospace;font-size:13px;word-break:break-all;background:white;padding:8px;border-radius:8px;">${escapeHtml(activeKey.key)}</div></div>`;}});if(html==='<div style="max-height:400px;overflow-y:auto;">'){html+='<div style="text-align:center;color:#999;padding:20px;">暂无配置的API Key</div>';}html+='</div>';showModal('已配置的API密钥',html,false);}
