window.deleteMessage=async function(index,role){showModal('确认','确定删除这条消息吗？',false,async()=>{try{const res=await fetch('/api/delete-message',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({token,historyId:currentHistoryId,messageIndex:index,role})});const data=await res.json();if(data.success){await loadHistoryById(currentHistoryId);}else{showModal('错误',data.error||'删除失败');}}catch(e){showModal('错误','删除失败：'+e.message);}});};
window.editMessage=async function(index,role){const msgWrapper=document.getElementById('chatMessages').children[index];if(!msgWrapper)return;const msgDiv=msgWrapper.querySelector('.message');const contentDiv=msgWrapper.querySelector('.message-content');let content=contentDiv?contentDiv.innerText:msgDiv.innerText;if(role==='user'){showModal('编辑用户消息','',true,async(newContent)=>{try{const res=await fetch('/api/edit-user-message',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({token,historyId:currentHistoryId,messageIndex:index,newContent})});const data=await res.json();if(data.success){branches=data.branches;currentBranchIndex=data.newBranchIndex;renderMessages(data.messages);showBranchNav();for(let i=index+1;i<document.getElementById('chatMessages').children.length;i++){document.getElementById('chatMessages').children[i].remove();}sendMessage();}}catch(e){}},content);}else{showModal('编辑AI回复','',true,async(newContent)=>{try{const res=await fetch('/api/update-message',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({token,historyId:currentHistoryId,messageIndex:index,role,content:newContent})});const data=await res.json();if(data.success){const provider=providers.find(p=>p.id===selectedProviderId);let display=newContent;display=replaceFileOps(display);if(currentConfigs.markdown){display=marked.parse(display);}msgDiv.innerHTML=`<div style="display:flex;gap:12px;"><img src="${provider?provider.icon:'/image/user.svg'}" style="width:32px;height:32px;border-radius:50%;object-fit:cover;margin-left:-36px;"><div class="message-content" style="flex:1;">${display}</div></div>`;msgWrapper.innerHTML+=getMessageActions(index,role);hljs.highlightAll();}}catch(e){}},content);}};
window.regenerateMessage=async function(index,role){if(role==='user')return;const msgWrapper=document.getElementById('chatMessages').children[index];if(!msgWrapper)return;const msgDiv=msgWrapper.querySelector('.message');const messages=Array.from(document.getElementById('chatMessages').children);const userMsgIndex=index-1;if(userMsgIndex<0)return;const userMsgWrapper=messages[userMsgIndex];const userContent=userMsgWrapper.querySelector('.message-content')?userMsgWrapper.querySelector('.message-content').innerText:userMsgWrapper.innerText;const provider=providers.find(p=>p.id===selectedProviderId);msgDiv.innerHTML='<div style="display:flex;gap:12px;"><img src="'+(provider?provider.icon:'/image/user.svg')+'" style="width:32px;height:32px;border-radius:50%;object-fit:cover;margin-left:-36px;"><div class="message-content" style="flex:1;"><span class="loading"></span>思考中</div></div>';let reasoning='';let content='';let lastSent='';try{const res=await fetch('/api/chat',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({message:userContent,providerId:selectedProviderId,model:selectedModel,token,historyId:currentHistoryId,folder:currentPublicFolder,enablePlugins:currentConfigs.enablePlugins})});if(!res.ok)throw new Error('请求失败');const reader=res.body.getReader();const decoder=new TextDecoder();let buffer='';while(true){const{value,done}=await reader.read();if(done)break;const chunk=decoder.decode(value,{stream:true});buffer+=chunk;const lines=buffer.split('\n');buffer=lines.pop()||'';for(const line of lines){if(line.startsWith('data: ')&&line!=='data: [DONE]'){try{const data=JSON.parse(line.slice(6));if(data.reasoning){reasoning=data.reasoning;}if(data.content&&data.content!==lastSent){lastSent=data.content;content=data.content;let display=content;let reasoningHtml=reasoning?`<div class="reasoning">💭 ${escapeHtml(reasoning)}</div>`:'';display=replaceFileOps(display);if(currentConfigs.markdown){display=marked.parse(display);}msgDiv.innerHTML=`<div style="display:flex;gap:12px;"><img src="${provider?provider.icon:'/image/user.svg'}" style="width:32px;height:32px;border-radius:50%;object-fit:cover;margin-left:-36px;"><div class="message-content" style="flex:1;">${display}</div></div>${reasoningHtml}`;hljs.highlightAll();}}catch(e){}}}}}catch(e){msgDiv.innerHTML=`<div style="display:flex;gap:12px;"><img src="${provider?provider.icon:'/image/user.svg'}" style="width:32px;height:32px;border-radius:50%;object-fit:cover;margin-left:-36px;"><div class="message-content" style="flex:1;">❌ 重新生成失败: ${e.message}</div></div>`;}};
window.deleteHistory=async function(historyId){showModal('确认','确定删除这个历史会话吗？',false,async()=>{try{await fetch(`/api/history/${historyId}?token=${token}`,{method:'DELETE'});loadHistories();loadHistoriesDropdown();if(currentHistoryId===historyId){newChat();}}catch(e){showModal('错误','删除失败');}});};
window.toggleFileSelect=function(path){const index=selectedFiles.indexOf(path);if(index===-1){selectedFiles.push(path);}else{selectedFiles.splice(index,1);}loadFiles(currentFilePath);};
window.sendToChat=function(path){const file=selectedFiles.length?selectedFiles:[path];let readCmd='请帮我读取以下文件内容：\n';file.forEach(f=>{readCmd+=`[+#]${f}[+#]\n`;});document.getElementById('chatInput').value=readCmd;document.querySelector('.nav-item[data-pane="chat"]').click();};
window.renameFile=async function(path,oldName){showModal('重命名文件','请输入新文件名',true,async(newName)=>{if(!newName||newName===oldName)return;try{await fetch('/api/rename-file',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({oldPath:path,newName,folder:currentPublicFolder,token})});loadFiles(currentFilePath);}catch(e){}},oldName);};
window.moveFile=async function(path){showModal('移动文件','请输入目标文件夹路径（相对于公共目录）',true,async(destDir)=>{if(!destDir)return;try{await fetch('/api/move-file',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({sourcePath:path,destDir,folder:currentPublicFolder,token})});loadFiles(currentFilePath);}catch(e){}});};
window.deleteFile=async function(path){showModal('确认','确定删除这个文件/文件夹吗？',false,async()=>{try{await fetch('/api/delete-file',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({filePath:path,folder:currentPublicFolder,token})});loadFiles(currentFilePath);}catch(e){}});};
document.getElementById('uploadFileBtn')?.addEventListener('click',()=>{document.getElementById('fileUpload').click();});
document.getElementById('fileUpload')?.addEventListener('change',async(e)=>{if(adminControls.disablePublicDirWrite&&localStorage.getItem('username')!=='admin'){showModal('提示','管理员已禁用文件上传');e.target.value='';return;}const files=e.target.files;if(!files.length)return;showUploadProgressModal(files.length);let uploadXHR;for(let i=0;i<files.length;i++){const file=files[i];const formData=new FormData();formData.append('file',file);formData.append('dir',currentFilePath);formData.append('folder',currentPublicFolder);formData.append('token',token);await new Promise((resolve,reject)=>{const xhr=new XMLHttpRequest();uploadXHR=xhr;xhr.open('POST','/api/upload',true);xhr.upload.onprogress=(pe)=>{if(pe.lengthComputable){const percent=Math.round((pe.loaded/pe.total)*100);updateUploadProgress(i,percent);}};xhr.onload=()=>{if(xhr.status===200){resolve();}else{reject(new Error('上传失败'));}};xhr.onerror=()=>reject(new Error('网络错误'));xhr.send(formData);});}closeUploadModal();loadFiles(currentFilePath);e.target.value='';});
document.getElementById('createFolderBtn')?.addEventListener('click',async()=>{showModal('新建文件夹','请输入文件夹名称',true,async(folderName)=>{if(!folderName)return;const folderPath=currentFilePath?`${currentFilePath}/${folderName}`:folderName;try{await fetch('/api/create-folder',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({folderPath,folder:currentPublicFolder,token})});loadFiles(currentFilePath);}catch(e){}});});
document.getElementById('langZhBtn')?.addEventListener('click',()=>{currentLang='zh';document.getElementById('langZhBtn').classList.add('active');document.getElementById('langEnBtn').classList.remove('active');loadNotice();});
document.getElementById('langEnBtn')?.addEventListener('click',()=>{currentLang='en';document.getElementById('langEnBtn').classList.add('active');document.getElementById('langZhBtn').classList.remove('active');loadNotice();});
document.getElementById('saveNoticeBtn')?.addEventListener('click',async()=>{const content=document.getElementById('noticeEditor').value;try{await fetch(`/api/notice/${currentLang}`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({content})});showModal('成功','保存成功');}catch(e){}});
document.getElementById('addProviderBtn')?.addEventListener('click',async function(){try{const res=await fetch('/api/frameworks');const frameworks=await res.json();let cardsHtml='';frameworks.forEach(f=>{cardsHtml+=`<div class="new-framework-card" data-framework="${f.id}" style="border:2px solid #f0f0f0;border-radius:16px;padding:20px;cursor:pointer;display:flex;flex-direction:column;align-items:center;gap:10px;background:#fafafc;"><img src="${f.icon}" style="width:60px;height:60px;border-radius:12px;object-fit:contain;" onerror="this.src='/image/user.svg'"><div style="font-weight:600;font-size:18px;">${f.name}</div><div style="font-size:13px;color:#666;text-align:center;">${f.description||''}</div></div>`;});const modal=document.createElement('div');modal.id='newProviderModal';modal.className='modal-overlay';modal.style.cssText='display:flex;z-index:10001;';modal.innerHTML=`<div class="modal-content" style="width:90%;max-width:1200px;display:flex;flex-direction:column;"><div class="modal-title" style="font-size:24px;font-weight:600;margin-bottom:20px;">新增模型提供商</div><div class="modal-body" style="flex:1;overflow-y:auto;max-height:70vh;"><div style="margin-bottom:16px;font-size:16px;font-weight:500;">选择框架</div><div style="display:grid;grid-template-columns:repeat(5,1fr);gap:0px;margin-bottom:20px;">${cardsHtml}</div><input id="newProviderName" class="modal-input" style="width:100%;padding:15px;border-radius:12px;border:2px solid #f0f0f0;font-size:16px;" placeholder="请输入提供商名称"></div><div class="modal-buttons" style="display:flex;gap:12px;justify-content:flex-end;margin-top:20px;"><button id="newProviderConfirm" class="modal-btn confirm" style="padding:12px 30px;border-radius:12px;border:none;background:#000;color:white;font-size:16px;cursor:pointer;">确认</button><button id="newProviderCancel" class="modal-btn cancel" style="padding:12px 30px;border-radius:12px;border:1px solid #ddd;background:white;font-size:16px;cursor:pointer;">取消</button></div></div>`;document.body.appendChild(modal);let selectedFramework=null;document.querySelectorAll('.new-framework-card').forEach(card=>{card.addEventListener('click',function(){document.querySelectorAll('.new-framework-card').forEach(c=>c.style.border='2px solid #f0f0f0');this.style.border='2px solid #000';if(document.getElementById('app').classList.contains('dark-mode'))this.style.border='2px solid #00aaff';selectedFramework=this.dataset.framework;});});document.getElementById('newProviderConfirm').onclick=function(){const name=document.getElementById('newProviderName').value;if(!name||!selectedFramework){alert('请选择框架并输入名称');return;}const framework=frameworks.find(f=>f.id===selectedFramework);if(!framework)return;fetch(`/api/providers?token=${token}`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({name,url:framework.url,modelsUrl:framework.modelsUrl,icon:framework.icon})}).then(()=>{modal.remove();showModal('成功','✅ 提供商添加成功');loadProviders();}).catch(()=>{modal.remove();showModal('错误','添加失败');});};document.getElementById('newProviderCancel').onclick=function(){modal.remove();};}catch(e){showModal('错误','加载框架列表失败');}});
document.getElementById('saveConfigBtn')?.addEventListener('click',async()=>{const config={temperature:parseFloat(document.getElementById('configTemp')?.value)||0.6,maxTokens:parseInt(document.getElementById('configMaxTokens')?.value)||2000,topP:parseFloat(document.getElementById('configTopP')?.value)||0.9,topK:parseInt(document.getElementById('configTopK')?.value)||40,streamResponse:document.getElementById('configStreamResponse')?.checked,showTokenUsage:document.getElementById('configShowTokenUsage')?.checked,autoTitle:document.getElementById('configAutoTitle')?.checked,safeMode:document.getElementById('configSafeMode')?.checked,customCursor:document.getElementById('configCustomCursor')?.checked,showMessageActions:document.getElementById('configShowMessageActions')?.checked,darkMode:document.getElementById('configDarkMode')?.checked,titleModel:document.getElementById('configTitleModel')?.value,persistentFolder:document.getElementById('configPersistentFolder')?.value,systemPrompt:document.getElementById('configSystemPrompt')?.value||'',modelPrompt:document.getElementById('configModelPrompt')?.value||'',markdown:true,showUpdateNotice:document.getElementById('configShowUpdateNotice')?.checked,fontFamily:document.getElementById('configFontFamily')?.value||'default',messageAnimation:document.getElementById('configMessageAnimation')?.value||'fade',showModelAvatar:document.getElementById('configShowModelAvatar')?.checked,enablePlugins:document.getElementById('configEnablePlugins')?.checked,autoScroll: document.getElementById('configAutoScroll')?.checked,showTimestamp: document.getElementById('configShowTimestamp')?.checked,compactMode: document.getElementById('configCompactMode')?.checked,messageWidth: document.getElementById('configMessageWidth')?.value,};try{await fetch(`/api/configs?token=${token}`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(config)});showModal('成功','✅ 参数配置已保存');if(config.darkMode!==currentConfigs.darkMode){if(config.darkMode){document.getElementById('app').classList.add('dark-mode');document.getElementById('splash')?.classList.add('dark-mode');document.getElementById('globalThemeIcon').innerHTML='<circle cx="12" cy="12" r="5"></circle><line x1="12" y1="1" x2="12" y2="3"></line><line x1="12" y1="21" x2="12" y2="23"></line><line x1="4.22" y1="4.22" x2="5.64" y2="5.64"></line><line x1="18.36" y1="18.36" x2="19.78" y2="19.78"></line><line x1="1" y1="12" x2="3" y2="12"></line><line x1="21" y1="12" x2="23" y2="12"></line><line x1="4.22" y1="19.78" x2="5.64" y2="18.36"></line><line x1="18.36" y1="5.64" x2="19.78" y2="4.22"></line>';}else{document.getElementById('app').classList.remove('dark-mode');document.getElementById('splash')?.classList.remove('dark-mode');document.getElementById('globalThemeIcon').innerHTML='<path d="M21 12.79A9 9 0 1 1 11.21 3 7 7 0 0 0 21 12.79z"></path>';}}if(config.showUpdateNotice!==currentConfigs.showUpdateNotice){currentConfigs.showUpdateNotice=config.showUpdateNotice;if(!config.showUpdateNotice);else checkVersion();}currentConfigs=config;safeMode=config.safeMode;applyCursor();applyFont();}catch(e){}});
document.getElementById('resetConfigBtn')?.addEventListener('click',()=>{document.getElementById('configTemp').value='0.7';document.getElementById('configMaxTokens').value='2000';document.getElementById('configTopP').value='0.9';document.getElementById('configTopK').value='40';document.getElementById('configStreamResponse').checked=true;document.getElementById('configShowTokenUsage').checked=true;document.getElementById('configAutoTitle').checked=true;document.getElementById('configSafeMode').checked=true;document.getElementById('configCustomCursor').checked=true;document.getElementById('configShowModelAvatar').checked=true;document.getElementById('configShowMessageActions').checked=false;document.getElementById('configDarkMode').checked=false;document.getElementById('configTitleModel').value='';document.getElementById('configSystemPrompt').value='';document.getElementById('configModelPrompt').value='无';document.getElementById('configFontFamily').value='default';document.getElementById('configEnablePlugins').checked=true;});
document.getElementById('uploadPluginBtn')?.addEventListener('click',uploadPlugin);
socket.on('serverLog',(log)=>{apiCallCount++;const div=document.getElementById('logContent');if(div)div.innerHTML+=`<div style="margin-bottom:6px;color:${log.msg.includes('✅')?'#a5d6a5':log.msg.includes('❌')?'#ef9a9a':'#eaeaef'};">[${log.time}] ${escapeHtml(log.msg)}</div>`;});
window.selectProviderFramework=function(card){document.querySelectorAll('.provider-card-item').forEach(c=>c.style.border='2px solid #f0f0f0');card.style.border='2px solid #000';if(document.getElementById('app').classList.contains('dark-mode')){card.style.border='2px solid #00aaff';}window.selectedProviderFramework=card.dataset.framework;};
window.selectNewFramework=function(card){document.querySelectorAll('.new-framework-item').forEach(c=>c.style.border='2px solid #f0f0f0');card.style.border='2px solid #000';if(document.getElementById('app').classList.contains('dark-mode')){card.style.border='2px solid #00aaff';}window.selectedNewFramework=card.dataset.framework;};
let noticeEditMode=false;let noticeLastSaved=null;async function loadNotice(){try{const res=await fetch(`/api/notice/${currentLang}`);const data=await res.json();document.getElementById('noticeEditor').value=data.content;if(currentConfigs.markdown){document.getElementById('noticePreview').innerHTML=marked.parse(data.content);}else{document.getElementById('noticePreview').innerText=data.content;}if(noticeLastSaved){document.getElementById('noticeSavedTime').innerText=`上次保存: ${noticeLastSaved}`;}}catch(e){}}function toggleNoticeEdit(){noticeEditMode=!noticeEditMode;const editor=document.getElementById('noticeEditor');const preview=document.getElementById('noticePreview');const editBtn=document.getElementById('editNoticeBtn');const saveBtn=document.getElementById('saveNoticeBtn');if(noticeEditMode){editor.style.display='block';preview.style.display='none';editBtn.style.display='none';saveBtn.style.display='inline-flex';}else{editor.style.display='none';preview.style.display='block';editBtn.style.display='inline-flex';saveBtn.style.display='none';}}
document.getElementById('privateChatInput')?.addEventListener('keydown',(e)=>{if(e.key==='Enter'&&!e.shiftKey){e.preventDefault();sendPrivateMessage();}});
document.getElementById('saveCustomPromptBtn')?.addEventListener('click',saveCustomPrompt);